// src/index.js
import React from 'react';
import ReactDOM from 'react-dom';
import './index.css'; // Optional, if you have styling

// Import the App component
import App from './App';

// Render the App component into the root element
ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
